const workspace = readFileSync(new URL('../src/views/workspace/WorkSpace.vue', import.meta.url), 'utf8')
const editor = readFileSync(new URL('../src/components/workspace/editor.js', import.meta.url), 'utf8')
const postApi = readFileSync(new URL('../src/api/postApi.js', import.meta.url), 'utf8')
const groupApi = readFileSync(new URL('../src/api/groupApi.js', import.meta.url), 'utf8')
