const workspaceDerivedState = readFileSync(new URL('../src/views/workspace/composables/useWorkspaceDerivedState.js', import.meta.url), 'utf8')
const workspacePanelTabsBlock = workspace.match(/const workspacePanelTabs = computed\(\(\) => \[([\s\S]*?)\]\)/)?.[0] || ''

const readWorkspaceFeatureSources = (dirUrl) =>
  readdirSync(dirUrl, { withFileTypes: true }).flatMap((entry) => {
    const childUrl = new URL(entry.name + (entry.isDirectory() ? '/' : ''), dirUrl)
    if (entry.isDirectory()) return readWorkspaceFeatureSources(childUrl)
    if (!/\.(css|js|vue)$/.test(entry.name) || entry.name.endsWith('.test.js')) return []
    return readFileSync(childUrl, 'utf8')
  })

const workspaceFeatureSources = [
  workspace,
  ...readWorkspaceFeatureSources(new URL('../src/views/workspace/', import.meta.url)),
].join('\\n')

const editorFeatureSources = [
  editor,
  ...readWorkspaceFeatureSources(new URL('../src/components/workspace/', import.meta.url)),
].join('\\n')

